```spl
// top — valeurs les plus fréquentes (avec % automatique)
index=main
| top 10 src_ip
// Résultat : src_ip | count | percent

// top sur plusieurs champs
index=security EventCode=4625
| top 5 src_ip BY Account
// Top 5 IPs par compte ciblé

// Désactiver le pourcentage
| top 10 src_ip showperc=false

// rare — valeurs les plus rares (inverse de top)
index=main
| rare 5 command
// Commandes les moins utilisées = potentiellement suspectes

// timechart — statistiques dans le temps
index=security EventCode=4625
| timechart count BY EventCode span=1h
// Graphe : un axe par valeur d'EventCode, span=1h = tranches horaires

index=main status>=400
| timechart count span=30m
```
